function solve(s) {
    // 1. Calculate Frequencies
    const freqMap = new Map();
    for (const char of s) {
        freqMap.set(char, (freqMap.get(char) || 0) + 1);
    }

    // Helper function to find the mirror character
    const getMirror = (c) => {
        const charCode = c.charCodeAt(0);
        if (c >= 'a' && c <= 'z') {
            // Letter: 'a' -> 'z', 'b' -> 'y'
            // Position from 'a': charCode - 'a'.charCodeAt(0)
            const offset = charCode - 'a'.charCodeAt(0);
            const mirroredOffset = 25 - offset;
            return String.fromCharCode('a'.charCodeAt(0) + mirroredOffset);
        } else if (c >= '0' && c <= '9') {
            // Digit: '0' -> '9', '1' -> '8'
            // Position from '0': charCode - '0'.charCodeAt(0)
            const offset = charCode - '0'.charCodeAt(0);
            const mirroredOffset = 9 - offset;
            return String.fromCharCode('0'.charCodeAt(0) + mirroredOffset);
        }
        return null; 
    };

    let totalSum = 0;

    // Set to track characters already included in a counted pair (c, m) or (m, c)
    const processedCharacters = new Set();

    // 2. Iterate over unique characters present in s
    for (const c of freqMap.keys()) {
        if (processedCharacters.has(c)) {
            continue;
        }

        const m = getMirror(c);

        // Mark both c and m as processed to ensure the pair is only counted once
        processedCharacters.add(c);
        processedCharacters.add(m);

        // Calculate frequencies. If m is not in the string, its frequency is 0.
        const freq_c = freqMap.get(c);
        const freq_m = freqMap.get(m) || 0;

        // Calculate difference and add to sum
        totalSum += Math.abs(freq_c - freq_m);
    }

    return totalSum;
}

